with open('Templates/login.html', 'r', encoding='utf-8') as f:
    content = f.read()

# Replace the lucide window destructuring
content = re.sub(r"const\s*\{\s*Globe.*?\}\s*=\s*window\.lucide;", svg_defs, content, flags=re.DOTALL)

with open('Templates/login.html', 'w', encoding='utf-8') as f:
    f.write(content)
